export const DAILY_CHALLENGE_TASK_MAP: Record<string, DailyChallengeTask> = Object.fromEntries(
  DAILY_CHALLENGE_TASKS.map((t) => [t.id, t]),
);

/** Get all tasks for a given language/tech id */
export function getTasksForLanguage(techId: string): DailyChallengeTask[] {
  return DAILY_CHALLENGE_TASKS.filter((t) => t.language === techId);
}

/** Get a task by id */
export function getTaskById(id: string): DailyChallengeTask | undefined {
  return DAILY_CHALLENGE_TASK_MAP[id];
}

/** Select a pool of tasks for a user based on their selected languages.
 * Returns up to 60 tasks per language, shuffled into a single pool. */
export function selectPoolForLanguages(languageIds: string[], seed?: number): string[] {
  const all: DailyChallengeTask[] = [];
  for (const lang of languageIds) {
    all.push(...getTasksForLanguage(lang));
  }
  // Simple deterministic shuffle based on seed (or Date.now())
  const rng = seed ?? Date.now();
  const shuffled = [...all].sort((a, b) => {
    const ha = hashStr(a.id + rng);
    const hb = hashStr(b.id + rng);
    return ha - hb;
  });
  return shuffled.map((t) => t.id);
}

function hashStr(s: string): number {
  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0;
  }
  return h;
}
